// Input: Relation R, decomposed relations R1, R2
// Output: TRUE if lossless, FALSE otherwise

FUNCTION CheckLosslessJoin(R, R1, R2):
 // Find common attributes
 common = R1.attributes ∩ R2.attributes

 // Check if common attributes form key for R1 or R2
 IF IsKey(R1, common) OR IsKey(R2, common):
 RETURN TRUE
 ELSE:
 RETURN FALSE

FUNCTION IsKey(Relation, Attributes):
 // Check if Attributes functionally determine all
 // attributes in Relation
 closure = ComputeClosure(Attributes, Relation.fd)
 IF closure ⊇ Relation.attributes:
 RETURN TRUE
 ELSE:
 RETURN FALSE

// Input: Relation R with attributes and FDs
// Output: Set of candidate keys

FUNCTION FindCandidateKeys(R):
 attributes = R.attributes
 fds = R.functionalDependencies

 // Step 1: Find attributes that never appear on RHS
 leftOnly = GetLHSOnlyAttributes(fds)

 // Step 2: Find attributes that never appear on LHS
 rightOnly = GetRHSOnlyAttributes(fds)

 // Step 3: Start with leftOnly attributes as base
 // Compute closure, if full relation then candidate key
 // Else add attributes one by one from remaining

 result = empty set
 candidates = [leftOnly] // Start with minimal set

 FOR each candidate IN candidates:
 closure = ComputeClosure(candidate, fds)
 IF closure == attributes:
 result.add(candidate)
 ELSE:
 // Try adding attributes from rightOnly
 FOR attr IN rightOnly:
 IF candidate ∪ {attr} NOT IN result:
 newCand = candidate ∪ {attr}
 closure = ComputeClosure(newCand, fds)
 IF closure == attributes:
 result.add(newCand)

 RETURN MinimalKeys(result) // Remove supersets
